const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.stripe&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;
if (!creds.stripe_api_key) {
  return [{ json: { error: 'Stripe API key not configured. Expected Secret (sk_test_...) or Restricted (rk_test_...) key.' } }];
}

const API = 'https://api.stripe.com/v1';
const basic = Buffer.from(creds.stripe_api_key + ':').toString('base64');
const authHeaders = { 'Authorization': 'Basic ' + basic };
const formHeaders = { ...authHeaders, 'Content-Type': 'application/x-www-form-urlencoded' };
const isLive = /^(sk|rk)_live_/.test(creds.stripe_api_key);
const modeTag = isLive ? ' [LIVE]' : ' [test]';

function truncate(text, max) {
  max = max || 5000;
  if (text.length > max) return text.substring(0, max) + '\n\n... (truncated, ' + text.length + ' chars total)';
  return text;
}

function fmtAmount(amount, currency) {
  if (amount === null || amount === undefined) return '?';
  const c = (currency || 'usd').toLowerCase();
  const zero = ['bif','clp','djf','gnf','jpy','kmf','krw','mga','pyg','rwf','ugx','vnd','vuv','xaf','xof','xpf'];
  const divisor = zero.includes(c) ? 1 : 100;
  const val = (Number(amount) / divisor).toFixed(divisor === 1 ? 0 : 2);
  return val + ' ' + c.toUpperCase();
}

function fmtDate(ts) {
  if (!ts) return '';
  return new Date(Number(ts) * 1000).toISOString().substring(0, 10);
}

function buildForm(obj) {
  const parts = [];
  for (const [k, v] of Object.entries(obj || {})) {
    if (v === undefined || v === null || v === '') continue;
    parts.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
  }
  return parts.join('&');
}

async function stripeGet(path) {
  return await helpers.httpRequest({ method: 'GET', url: API + path, headers: authHeaders, json: true });
}

async function stripePost(path, form) {
  return await helpers.httpRequest({ method: 'POST', url: API + path, headers: formHeaders, body: buildForm(form), json: true });
}

async function stripeDelete(path) {
  return await helpers.httpRequest({ method: 'DELETE', url: API + path, headers: authHeaders, json: true });
}

function errMsg(err) {
  if (err.response && err.response.body && err.response.body.error) return err.response.body.error.message;
  if (err.message) return err.message;
  return String(err);
}

// === list_customers ===
if (action === 'list_customers') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  try {
    const r = await stripeGet('/customers?limit=' + limit);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No customers.' + modeTag } }];
    let out = 'Customers' + modeTag + ' (' + items.length + '):\n';
    for (const c of items) out += '  ' + c.id + ' — ' + (c.name || '(no name)') + (c.email ? ' <' + c.email + '>' : '') + ' created: ' + fmtDate(c.created) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_customers: ' + errMsg(err) } }]; }

// === search_customers ===
} else if (action === 'search_customers') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required. Stripe search syntax: email:"x@y.com", name:"Acme", metadata["order_id"]:"123".' } }];
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  try {
    const r = await stripeGet('/customers/search?query=' + encodeURIComponent(query) + '&limit=' + limit);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No customers matched "' + query + '".' + modeTag } }];
    let out = 'Matches' + modeTag + ' (' + items.length + '):\n';
    for (const c of items) out += '  ' + c.id + ' — ' + (c.name || '(no name)') + (c.email ? ' <' + c.email + '>' : '') + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe search_customers: ' + errMsg(err) } }]; }

// === get_customer ===
} else if (action === 'get_customer') {
  const id = input.customer_id;
  if (!id) return [{ json: { error: 'Parameter "customer_id" is required (cus_...).' } }];
  try {
    const c = await stripeGet('/customers/' + encodeURIComponent(id));
    let out = 'Customer ' + c.id + modeTag + '\n';
    out += 'Name: ' + (c.name || '(none)') + '\n';
    if (c.email) out += 'Email: ' + c.email + '\n';
    if (c.phone) out += 'Phone: ' + c.phone + '\n';
    if (c.description) out += 'Description: ' + c.description + '\n';
    out += 'Created: ' + fmtDate(c.created) + '\n';
    if (c.balance !== undefined) out += 'Balance: ' + fmtAmount(c.balance, c.currency || 'usd') + '\n';
    if (c.delinquent) out += 'DELINQUENT\n';
    if (c.metadata && Object.keys(c.metadata).length) out += 'Metadata: ' + JSON.stringify(c.metadata) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe get_customer: ' + errMsg(err) } }]; }

// === create_customer ===
} else if (action === 'create_customer') {
  if (!input.name && !input.email) return [{ json: { error: 'At least one of "name" or "email" is required.' } }];
  const form = {};
  if (input.name) form.name = input.name;
  if (input.email) form.email = input.email;
  if (input.phone) form.phone = input.phone;
  if (input.description) form.description = input.description;
  try {
    const c = await stripePost('/customers', form);
    return [{ json: { result: 'Customer created' + modeTag + ': ' + c.id + ' — ' + (c.name || c.email || '') } }];
  } catch (err) { return [{ json: { error: 'Stripe create_customer: ' + errMsg(err) } }]; }

// === update_customer ===
} else if (action === 'update_customer') {
  const id = input.customer_id;
  if (!id) return [{ json: { error: 'Parameter "customer_id" is required.' } }];
  const form = {};
  if (input.name !== undefined) form.name = input.name;
  if (input.email !== undefined) form.email = input.email;
  if (input.phone !== undefined) form.phone = input.phone;
  if (input.description !== undefined) form.description = input.description;
  if (Object.keys(form).length === 0) return [{ json: { error: 'Provide at least one field: name, email, phone, description.' } }];
  try {
    const c = await stripePost('/customers/' + encodeURIComponent(id), form);
    return [{ json: { result: 'Customer ' + c.id + ' updated' + modeTag + '.' } }];
  } catch (err) { return [{ json: { error: 'Stripe update_customer: ' + errMsg(err) } }]; }

// === list_payments (payment_intents) ===
} else if (action === 'list_payments') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  let path = '/payment_intents?limit=' + limit;
  if (input.customer_id) path += '&customer=' + encodeURIComponent(input.customer_id);
  try {
    const r = await stripeGet(path);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No payments.' + modeTag } }];
    let out = 'PaymentIntents' + modeTag + ' (' + items.length + '):\n';
    for (const p of items) {
      out += '  ' + p.id + ' [' + p.status + '] ' + fmtAmount(p.amount, p.currency) + ' ' + fmtDate(p.created);
      if (p.customer) out += ' cust: ' + p.customer;
      if (p.description) out += ' "' + p.description.substring(0, 40) + '"';
      out += '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_payments: ' + errMsg(err) } }]; }

// === get_payment ===
} else if (action === 'get_payment') {
  const id = input.payment_id;
  if (!id) return [{ json: { error: 'Parameter "payment_id" is required (pi_...).' } }];
  try {
    const p = await stripeGet('/payment_intents/' + encodeURIComponent(id));
    let out = 'Payment ' + p.id + modeTag + '\n';
    out += 'Status: ' + p.status + '\n';
    out += 'Amount: ' + fmtAmount(p.amount, p.currency) + '\n';
    if (p.amount_received !== undefined) out += 'Received: ' + fmtAmount(p.amount_received, p.currency) + '\n';
    if (p.customer) out += 'Customer: ' + p.customer + '\n';
    if (p.description) out += 'Description: ' + p.description + '\n';
    if (p.latest_charge) out += 'Latest charge: ' + p.latest_charge + '\n';
    out += 'Created: ' + fmtDate(p.created) + '\n';
    if (p.last_payment_error) out += 'Last error: ' + p.last_payment_error.message + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe get_payment: ' + errMsg(err) } }]; }

// === list_charges ===
} else if (action === 'list_charges') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  let path = '/charges?limit=' + limit;
  if (input.customer_id) path += '&customer=' + encodeURIComponent(input.customer_id);
  try {
    const r = await stripeGet(path);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No charges.' + modeTag } }];
    let out = 'Charges' + modeTag + ' (' + items.length + '):\n';
    for (const c of items) {
      out += '  ' + c.id + ' [' + c.status + ']' + (c.refunded ? ' REFUNDED' : '') + ' ' + fmtAmount(c.amount, c.currency) + ' ' + fmtDate(c.created);
      if (c.customer) out += ' cust: ' + c.customer;
      out += '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_charges: ' + errMsg(err) } }]; }

// === list_invoices ===
} else if (action === 'list_invoices') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  let path = '/invoices?limit=' + limit;
  if (input.customer_id) path += '&customer=' + encodeURIComponent(input.customer_id);
  if (input.status) path += '&status=' + encodeURIComponent(input.status);
  try {
    const r = await stripeGet(path);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No invoices.' + modeTag } }];
    let out = 'Invoices' + modeTag + ' (' + items.length + '):\n';
    for (const i of items) {
      out += '  ' + i.id + ' [' + i.status + '] ' + fmtAmount(i.total, i.currency) + ' ' + fmtDate(i.created);
      if (i.customer_email) out += ' ' + i.customer_email;
      if (i.number) out += ' #' + i.number;
      out += '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_invoices: ' + errMsg(err) } }]; }

// === get_invoice ===
} else if (action === 'get_invoice') {
  const id = input.invoice_id;
  if (!id) return [{ json: { error: 'Parameter "invoice_id" is required (in_...).' } }];
  try {
    const i = await stripeGet('/invoices/' + encodeURIComponent(id));
    let out = 'Invoice ' + i.id + modeTag + '\n';
    if (i.number) out += 'Number: ' + i.number + '\n';
    out += 'Status: ' + i.status + '\n';
    out += 'Total: ' + fmtAmount(i.total, i.currency) + '\n';
    out += 'Subtotal: ' + fmtAmount(i.subtotal, i.currency) + '\n';
    if (i.amount_paid !== undefined) out += 'Paid: ' + fmtAmount(i.amount_paid, i.currency) + '\n';
    if (i.amount_due !== undefined) out += 'Due: ' + fmtAmount(i.amount_due, i.currency) + '\n';
    if (i.customer) out += 'Customer: ' + i.customer + (i.customer_email ? ' (' + i.customer_email + ')' : '') + '\n';
    out += 'Created: ' + fmtDate(i.created) + '\n';
    if (i.due_date) out += 'Due date: ' + fmtDate(i.due_date) + '\n';
    if (i.hosted_invoice_url) out += 'Hosted URL: ' + i.hosted_invoice_url + '\n';
    if (i.invoice_pdf) out += 'PDF: ' + i.invoice_pdf + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe get_invoice: ' + errMsg(err) } }]; }

// === create_invoice ===
} else if (action === 'create_invoice') {
  const customer = input.customer_id;
  if (!customer) return [{ json: { error: 'Parameter "customer_id" is required (cus_...).' } }];
  const form = { customer };
  if (input.description) form.description = input.description;
  if (input.days_until_due) form.collection_method = 'send_invoice', form.days_until_due = input.days_until_due;
  try {
    const i = await stripePost('/invoices', form);
    return [{ json: { result: 'Draft invoice created' + modeTag + ': ' + i.id + ' (status: ' + i.status + '). Add line items via Stripe dashboard or API before finalizing.' } }];
  } catch (err) { return [{ json: { error: 'Stripe create_invoice: ' + errMsg(err) } }]; }

// === list_subscriptions ===
} else if (action === 'list_subscriptions') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  let path = '/subscriptions?limit=' + limit;
  if (input.customer_id) path += '&customer=' + encodeURIComponent(input.customer_id);
  if (input.status) path += '&status=' + encodeURIComponent(input.status);
  try {
    const r = await stripeGet(path);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No subscriptions.' + modeTag } }];
    let out = 'Subscriptions' + modeTag + ' (' + items.length + '):\n';
    for (const s of items) {
      const plan = (s.items && s.items.data && s.items.data[0] ? s.items.data[0].plan : null);
      out += '  ' + s.id + ' [' + s.status + '] cust: ' + s.customer;
      if (plan) out += ' ' + fmtAmount(plan.amount, plan.currency) + '/' + plan.interval;
      out += ' renews: ' + fmtDate(s.current_period_end) + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_subscriptions: ' + errMsg(err) } }]; }

// === get_subscription ===
} else if (action === 'get_subscription') {
  const id = input.subscription_id;
  if (!id) return [{ json: { error: 'Parameter "subscription_id" is required (sub_...).' } }];
  try {
    const s = await stripeGet('/subscriptions/' + encodeURIComponent(id));
    let out = 'Subscription ' + s.id + modeTag + '\n';
    out += 'Status: ' + s.status + '\n';
    out += 'Customer: ' + s.customer + '\n';
    out += 'Current period: ' + fmtDate(s.current_period_start) + ' — ' + fmtDate(s.current_period_end) + '\n';
    if (s.cancel_at_period_end) out += 'CANCELS at period end\n';
    if (s.items && s.items.data) {
      out += 'Items:\n';
      for (const it of s.items.data) {
        const p = it.plan;
        out += '  ' + it.id + ': ' + fmtAmount(p.amount, p.currency) + '/' + p.interval + ' x' + it.quantity + '\n';
      }
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe get_subscription: ' + errMsg(err) } }]; }

// === cancel_subscription ===
} else if (action === 'cancel_subscription') {
  const id = input.subscription_id;
  if (!id) return [{ json: { error: 'Parameter "subscription_id" is required (sub_...).' } }];
  try {
    const s = await stripeDelete('/subscriptions/' + encodeURIComponent(id));
    return [{ json: { result: 'Subscription ' + s.id + ' canceled' + modeTag + ' (status: ' + s.status + ').' } }];
  } catch (err) { return [{ json: { error: 'Stripe cancel_subscription: ' + errMsg(err) } }]; }

// === list_products ===
} else if (action === 'list_products') {
  const limit = Math.min(parseInt(input.limit) || 20, 100);
  let path = '/products?limit=' + limit;
  if (input.active !== undefined) path += '&active=' + (input.active === 'false' ? 'false' : 'true');
  try {
    const r = await stripeGet(path);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No products.' + modeTag } }];
    let out = 'Products' + modeTag + ' (' + items.length + '):\n';
    for (const p of items) out += '  ' + p.id + (p.active ? '' : ' [archived]') + ' — ' + p.name + (p.description ? ' — ' + p.description.substring(0, 60) : '') + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_products: ' + errMsg(err) } }]; }

// === list_prices ===
} else if (action === 'list_prices') {
  const limit = Math.min(parseInt(input.limit) || 20, 100);
  let path = '/prices?limit=' + limit;
  if (input.product_id) path += '&product=' + encodeURIComponent(input.product_id);
  if (input.active !== undefined) path += '&active=' + (input.active === 'false' ? 'false' : 'true');
  try {
    const r = await stripeGet(path);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No prices.' + modeTag } }];
    let out = 'Prices' + modeTag + ' (' + items.length + '):\n';
    for (const p of items) {
      out += '  ' + p.id + ' — ' + fmtAmount(p.unit_amount, p.currency);
      if (p.recurring) out += '/' + p.recurring.interval;
      out += ' (product: ' + p.product + ')';
      if (!p.active) out += ' [archived]';
      out += '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_prices: ' + errMsg(err) } }]; }

// === list_refunds ===
} else if (action === 'list_refunds') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  let path = '/refunds?limit=' + limit;
  if (input.charge_id) path += '&charge=' + encodeURIComponent(input.charge_id);
  if (input.payment_intent_id) path += '&payment_intent=' + encodeURIComponent(input.payment_intent_id);
  try {
    const r = await stripeGet(path);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No refunds.' + modeTag } }];
    let out = 'Refunds' + modeTag + ' (' + items.length + '):\n';
    for (const rf of items) out += '  ' + rf.id + ' [' + rf.status + '] ' + fmtAmount(rf.amount, rf.currency) + ' charge: ' + rf.charge + ' ' + fmtDate(rf.created) + (rf.reason ? ' reason: ' + rf.reason : '') + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_refunds: ' + errMsg(err) } }]; }

// === create_refund ===
} else if (action === 'create_refund') {
  if (!input.charge_id && !input.payment_intent_id) return [{ json: { error: 'Provide either "charge_id" (ch_...) or "payment_intent_id" (pi_...).' } }];
  const form = {};
  if (input.charge_id) form.charge = input.charge_id;
  else form.payment_intent = input.payment_intent_id;
  if (input.amount) form.amount = input.amount;
  if (input.reason) form.reason = input.reason;
  try {
    const rf = await stripePost('/refunds', form);
    return [{ json: { result: 'Refund created' + modeTag + ': ' + rf.id + ' [' + rf.status + '] ' + fmtAmount(rf.amount, rf.currency) + '.' } }];
  } catch (err) { return [{ json: { error: 'Stripe create_refund: ' + errMsg(err) } }]; }

// === get_balance ===
} else if (action === 'get_balance') {
  try {
    const b = await stripeGet('/balance');
    let out = 'Balance' + modeTag + '\n';
    out += 'Available:\n';
    for (const a of (b.available || [])) out += '  ' + fmtAmount(a.amount, a.currency) + '\n';
    out += 'Pending:\n';
    for (const p of (b.pending || [])) out += '  ' + fmtAmount(p.amount, p.currency) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe get_balance: ' + errMsg(err) } }]; }

// === list_balance_transactions ===
} else if (action === 'list_balance_transactions') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  let path = '/balance_transactions?limit=' + limit;
  if (input.type) path += '&type=' + encodeURIComponent(input.type);
  try {
    const r = await stripeGet(path);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No balance transactions.' + modeTag } }];
    let out = 'Balance transactions' + modeTag + ' (' + items.length + '):\n';
    for (const t of items) {
      out += '  ' + t.id + ' [' + t.type + '] ' + fmtAmount(t.amount, t.currency) + ' net: ' + fmtAmount(t.net, t.currency) + ' fee: ' + fmtAmount(t.fee, t.currency) + ' ' + fmtDate(t.created) + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_balance_transactions: ' + errMsg(err) } }]; }

// === list_payouts ===
} else if (action === 'list_payouts') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  try {
    const r = await stripeGet('/payouts?limit=' + limit);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No payouts.' + modeTag } }];
    let out = 'Payouts' + modeTag + ' (' + items.length + '):\n';
    for (const p of items) out += '  ' + p.id + ' [' + p.status + '] ' + fmtAmount(p.amount, p.currency) + ' arrival: ' + fmtDate(p.arrival_date) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_payouts: ' + errMsg(err) } }]; }

// === list_disputes ===
} else if (action === 'list_disputes') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  try {
    const r = await stripeGet('/disputes?limit=' + limit);
    const items = r.data || [];
    if (items.length === 0) return [{ json: { result: 'No disputes.' + modeTag } }];
    let out = 'Disputes' + modeTag + ' (' + items.length + '):\n';
    for (const d of items) out += '  ' + d.id + ' [' + d.status + '] ' + fmtAmount(d.amount, d.currency) + ' reason: ' + (d.reason || '?') + ' charge: ' + d.charge + ' ' + fmtDate(d.created) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'Stripe list_disputes: ' + errMsg(err) } }]; }

// === create_payment_link ===
} else if (action === 'create_payment_link') {
  const price = input.price_id;
  if (!price) return [{ json: { error: 'Parameter "price_id" is required (price_...). Use list_prices to find one.' } }];
  const qty = parseInt(input.quantity) || 1;
  const form = { 'line_items[0][price]': price, 'line_items[0][quantity]': String(qty) };
  try {
    const pl = await stripePost('/payment_links', form);
    return [{ json: { result: 'Payment link created' + modeTag + ': ' + pl.url + '\n(id: ' + pl.id + ')' } }];
  } catch (err) { return [{ json: { error: 'Stripe create_payment_link: ' + errMsg(err) } }]; }

} else {
